const stringifiedAst = "{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[14,15],\"inline\":false,\"attributes\":{\"level\":2},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[14,15],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[14,15],\"inline\":true,\"attributes\":{\"content\":\"Focus on Managing Verbal and Physical Conflicts\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":14},\"end\":{\"line\":15}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":14},\"end\":{\"line\":15}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":14},\"end\":{\"line\":15}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[16,17],\"inline\":false,\"attributes\":{\"level\":3},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[16,17],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[16,17],\"inline\":true,\"attributes\":{\"content\":\"1. Analyse existing and potential security vulnerabilities\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":16},\"end\":{\"line\":17}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":16},\"end\":{\"line\":17}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":16},\"end\":{\"line\":17}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[18,19],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[18,19],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[18,19],\"inline\":true,\"attributes\":{\"content\":\"Hospital establishments have structurally vulnerable zones: emergency departments, overcrowded waiting areas, isolated corridors and uncontrolled access. A precise mapping of these spaces, combined with an analysis of circulation flows, makes it possible to identify key points where the risk of verbal or physical conflict is statistically higher.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":18},\"end\":{\"line\":19}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":18},\"end\":{\"line\":19}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":18},\"end\":{\"line\":19}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[20,21],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[20,21],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[20,21],\"inline\":true,\"attributes\":{\"content\":\"Evaluating security protocols in place requires a critical and objective approach. It is necessary to audit existing procedures, question field teams and compare practices against national benchmarks. This audit highlights the gaps between theoretical measures and their actual implementation in daily work.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":20},\"end\":{\"line\":21}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":20},\"end\":{\"line\":21}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":20},\"end\":{\"line\":21}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[22,23],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[22,23],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[22,23],\"inline\":true,\"attributes\":{\"content\":\"Collecting and analysing data on past incidents forms the empirical basis for any improvement approach. By cataloguing the types of conflicts, their timing, their triggers and their protagonists, the establishment can draw out clear trends, anticipate risky situations and concentrate its resources on identified weak points.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":22},\"end\":{\"line\":23}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":22},\"end\":{\"line\":23}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":22},\"end\":{\"line\":23}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[25,26],\"inline\":false,\"attributes\":{\"level\":3},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[25,26],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[25,26],\"inline\":true,\"attributes\":{\"content\":\"2. Train teams to a common intervention protocol\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":25},\"end\":{\"line\":26}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":25},\"end\":{\"line\":26}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":25},\"end\":{\"line\":26}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[27,28],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[27,28],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[27,28],\"inline\":true,\"attributes\":{\"content\":\"An effective intervention protocol must describe precisely the steps to take when faced with a verbal or physical conflict: who intervenes first, how to alert reinforcements, what de-escalation techniques to prioritise. This common framework prevents dangerous improvisation and guarantees a coherent and coordinated response from all staff.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":27},\"end\":{\"line\":28}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":27},\"end\":{\"line\":28}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":27},\"end\":{\"line\":28}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[29,30],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[29,30],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[29,30],\"inline\":true,\"attributes\":{\"content\":\"Regular training is essential for the protocol to remain embedded in staff reflexes. Planned sessions – at least twice a year – allow integration of new arrivals, reinforcement of fundamentals for existing teams and updating of practices based on field feedback and the evolution of situations encountered.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":29},\"end\":{\"line\":30}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":29},\"end\":{\"line\":30}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":29},\"end\":{\"line\":30}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[31,32],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[31,32],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[31,32],\"inline\":true,\"attributes\":{\"content\":\"Practical exercises and simulations in realistic conditions significantly strengthen the assimilation of the protocol. Playing out conflict scenarios, alternating roles (healthcare provider, aggressor, mediator) and collectively debriefing after each exercise develops confidence, reduces stress in real situations and improves coordination between colleagues.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":31},\"end\":{\"line\":32}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":31},\"end\":{\"line\":32}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":31},\"end\":{\"line\":32}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[34,35],\"inline\":false,\"attributes\":{\"level\":3},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[34,35],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[34,35],\"inline\":true,\"attributes\":{\"content\":\"3. Drill teams on verbal and physical conflict scenarios\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":34},\"end\":{\"line\":35}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":34},\"end\":{\"line\":35}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":34},\"end\":{\"line\":35}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[36,37],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[36,37],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[36,37],\"inline\":true,\"attributes\":{\"content\":\"Drill scenarios must be grounded in the reality of the establishment: agitated patient in casualty, threatening visitor, conflict between patients in shared room. Drawing on documented real incidents ensures their relevance and promotes staff buy-in, who recognise in these situations problems they have already encountered or fear.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":36},\"end\":{\"line\":37}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":36},\"end\":{\"line\":37}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":36},\"end\":{\"line\":37}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[38,39],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[38,39],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[38,39],\"inline\":true,\"attributes\":{\"content\":\"Regular drill sessions – ideally monthly or fortnightly – maintain a high level of reactivity in teams. Repetition creates automaticity: faced with the stress of real conflict, staff do not have to think through the steps to follow, they apply them instinctively, which reduces response time and limits situation escalation.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":38},\"end\":{\"line\":39}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":38},\"end\":{\"line\":39}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":38},\"end\":{\"line\":39}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[40,41],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[40,41],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[40,41],\"inline\":true,\"attributes\":{\"content\":\"After each drill, structured experience feedback is organised: strengths, errors made, possible improvements. These collective analyses allow continuous refinement of scenarios, adjustment of taught techniques and documentation of emerging best practices. This continuous improvement cycle ensures the establishment's security practices continually evolve and remain in step with field realities.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":40},\"end\":{\"line\":41}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":40},\"end\":{\"line\":41}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":40},\"end\":{\"line\":41}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[43,44],\"inline\":false,\"attributes\":{\"level\":3},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[43,44],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[43,44],\"inline\":true,\"attributes\":{\"content\":\"4. Implement communication and signalling tools\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":43},\"end\":{\"line\":44}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":43},\"end\":{\"line\":44}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":43},\"end\":{\"line\":44}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[45,46],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[45,46],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[45,46],\"inline\":true,\"attributes\":{\"content\":\"Installation of appropriate alarm systems – silent alert buttons, zoned audio alarms, light signage – allows staff to quickly trigger an intervention without worsening the situation. Each identified risk zone should be prioritised, with devices accessible from several points in the room to ensure their usefulness under all circumstances.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":45},\"end\":{\"line\":46}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":45},\"end\":{\"line\":46}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":45},\"end\":{\"line\":46}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[47,48],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[47,48],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[47,48],\"inline\":true,\"attributes\":{\"content\":\"Dedicated communication tools for crisis situations complement the alert system: secure hand-helds, professional mobile applications, direct lines between services. These channels allow staff to coordinate interventions in real time, alert reinforcements and inform management without delay, even under high pressure.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":47},\"end\":{\"line\":48}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":47},\"end\":{\"line\":48}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":47},\"end\":{\"line\":48}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[49,50],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[49,50],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[49,50],\"inline\":true,\"attributes\":{\"content\":\"The reliability of equipment is a non-negotiable condition. A preventive maintenance plan must be formalised: weekly checks, monthly tests in realistic conditions, immediate replacement of faulty equipment. A security tool out of service at the critical moment is a gap as serious as its absence. The traceability of checks must be assured and accessible.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":49},\"end\":{\"line\":50}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":49},\"end\":{\"line\":50}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":49},\"end\":{\"line\":50}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[52,53],\"inline\":false,\"attributes\":{\"level\":3},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[52,53],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[52,53],\"inline\":true,\"attributes\":{\"content\":\"5. Create secure spaces for patients and staff\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":52},\"end\":{\"line\":53}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":52},\"end\":{\"line\":53}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":52},\"end\":{\"line\":53}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[54,55],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[54,55],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[54,55],\"inline\":true,\"attributes\":{\"content\":\"Refuge spaces – secure rooms fitted with reinforced locks, means of communication and clear signage – should be set up in each sensitive wing of the establishment. These \\\"panic rooms\\\", \\\"safe rooms\\\", provide immediate refuge in case of imminent threat and allow staff to take shelter while reinforcements arrive.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":54},\"end\":{\"line\":55}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":54},\"end\":{\"line\":55}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":54},\"end\":{\"line\":55}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[56,57],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[56,57],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[56,57],\"inline\":true,\"attributes\":{\"content\":\"The accessibility of these spaces determines their usefulness: they must be located less than thirty seconds' walk from risk zones, clearly marked with standardised pictograms, and free of any clutter. A map of secure spaces must be posted in passage areas and integrated into training materials.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":56},\"end\":{\"line\":57}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":56},\"end\":{\"line\":57}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":56},\"end\":{\"line\":57}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[58,59],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[58,59],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[58,59],\"inline\":true,\"attributes\":{\"content\":\"Training in the use of these spaces is crucial. Each staff member must know the location of the nearest refuges to their workstation, be able to reach them quickly and guide vulnerable patients there. Evacuation exercises to these spaces must be integrated into regular drill sessions.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":58},\"end\":{\"line\":59}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":58},\"end\":{\"line\":59}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":58},\"end\":{\"line\":59}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[61,62],\"inline\":false,\"attributes\":{\"level\":3},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[61,62],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[61,62],\"inline\":true,\"attributes\":{\"content\":\"6. Establish privileged connections with law enforcement and emergency services\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":61},\"end\":{\"line\":62}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":61},\"end\":{\"line\":62}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":61},\"end\":{\"line\":62}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[63,64],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[63,64],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[63,64],\"inline\":true,\"attributes\":{\"content\":\"Structured collaboration with local police and gendarmerie services is essential to anticipate crisis situations. This involves designating security contacts in each area, jointly developing intervention plans adapted to the establishment's configuration and sharing relevant information on identified risks.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":63},\"end\":{\"line\":64}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":63},\"end\":{\"line\":64}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":63},\"end\":{\"line\":64}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[65,66],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[65,66],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[65,66],\"inline\":true,\"attributes\":{\"content\":\"Joint exercises between medical personnel and law enforcement allow intervention plans to be tested in conditions close to reality. These simulations reveal coordination difficulties, misunderstandings about each person's role and actual intervention times. They also build the interpersonal relationships of trust essential in real crisis situations.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":65},\"end\":{\"line\":66}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":65},\"end\":{\"line\":66}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":65},\"end\":{\"line\":66}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[67,68],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[67,68],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[67,68],\"inline\":true,\"attributes\":{\"content\":\"Direct and priority communication channels must be established: dedicated telephone numbers, radio access to police dispatchers, automated alert protocols. These devices ensure rapid and reliable information transmission during an incident, reducing law enforcement response times and thus limiting the escalation of dangerous situations.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":67},\"end\":{\"line\":68}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":67},\"end\":{\"line\":68}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":67},\"end\":{\"line\":68}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[70,71],\"inline\":false,\"attributes\":{\"level\":3},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[70,71],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[70,71],\"inline\":true,\"attributes\":{\"content\":\"7. Ensure regular incident monitoring and continuously improve security practices\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":70},\"end\":{\"line\":71}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":70},\"end\":{\"line\":71}}}],\"type\":\"heading\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":70},\"end\":{\"line\":71}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[72,73],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[72,73],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[72,73],\"inline\":true,\"attributes\":{\"content\":\"A formalised incident monitoring system – digital register, standardised reporting form, clear information flow – allows every verbal or physical conflict that has occurred in the establishment to be documented. This exhaustive inventory is the prerequisite for any serious analysis and any improvement approach based on actual facts.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":72},\"end\":{\"line\":73}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":72},\"end\":{\"line\":73}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":72},\"end\":{\"line\":73}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[74,75],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[74,75],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[74,75],\"inline\":true,\"attributes\":{\"content\":\"Periodic analysis of collected data – monthly or quarterly depending on incident volume – allows identification of trends: risky times, most affected services, recurring aggressor profiles, frequent triggers. These lessons guide decisions to strengthen preventive measures where they are most needed, avoiding scatter of resources.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":74},\"end\":{\"line\":75}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":74},\"end\":{\"line\":75}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":74},\"end\":{\"line\":75}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[76,77],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[76,77],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[76,77],\"inline\":true,\"attributes\":{\"content\":\"Experience feedback from these analyses must be systematically translated into concrete actions: revision of intervention protocols, adaptation of drill scenarios, strengthening of targeted training. This virtuous cycle – analyse, adapt, train – ensures the establishment's security practices continually evolve and remain in step with field realities.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":76},\"end\":{\"line\":77}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":76},\"end\":{\"line\":77}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":76},\"end\":{\"line\":77}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[78,79],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[78,79],\"inline\":false,\"attributes\":{},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[78,79],\"inline\":true,\"attributes\":{\"marker\":\"*\"},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[78,79],\"inline\":true,\"attributes\":{\"content\":\"Our partner, \"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":78},\"end\":{\"line\":79}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[78,79],\"inline\":true,\"attributes\":{\"href\":\"https://yoursafety.training\"},\"children\":[{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[78,79],\"inline\":true,\"attributes\":{\"content\":\"Jérôme BOUTEILLER\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":78},\"end\":{\"line\":79}}}],\"type\":\"link\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":78},\"end\":{\"line\":79}}},{\"$$mdtype\":\"Node\",\"errors\":[],\"lines\":[78,79],\"inline\":true,\"attributes\":{\"content\":\", trains medical teams in managing patient violence and aggression, drawing on tried and tested de-escalation techniques adapted to the hospital context. Do not hesitate to contact him to benefit from expert knowledge and personalised support in implementing these recommendations. His courses are accredited by Agenas, Italian Ministry of Health, as part of continuing education for health professionals.\"},\"children\":[],\"type\":\"text\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":78},\"end\":{\"line\":79}}}],\"type\":\"em\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":78},\"end\":{\"line\":79}}}],\"type\":\"inline\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":78},\"end\":{\"line\":79}}}],\"type\":\"paragraph\",\"annotations\":[],\"slots\":{},\"location\":{\"start\":{\"line\":78},\"end\":{\"line\":79}}}],\"type\":\"document\",\"annotations\":[],\"slots\":{}}";

